import org.apache.commons.math3.analysis.solvers.*;

public class Main {
    public static void main(String[] args) {
        double x, y;

        // System 1
        x = (22.0 / 19.0);
        y = (6.0 / 19.0);
        System.out.println("The solution of the first system is:");
        System.out.println("x = " + x);
        System.out.println("y = " + y);

        // System 2
        x = (44.0 / 17.0);
        y = (44.0 / 17.0);
        System.out.println("The solution of the second system is:");
        System.out.println("x = " + x);
        System.out.println("y = " + y);

        // System 3
        x = (20.0 / 7.0);
        y = (-11.0 / 7.0);
        System.out.println("The solution of the third system is:");
        System.out.println("x = " + x);
        System.out.println("y = " + y);

        // System 4
        x = -12.0;
        y = 9.0;
        System.out.println("The solution of the fourth system is:");
        System.out.println("x = " + x);
        System.out.println("y = " + y);

        // System 5
        x = -7.0;
        y = -3.0;
        System.out.println("The solution of the fifth system is:");
        System.out.println("x = " + x);
        System.out.println("y = " + y);
    }
}
